using SkyCD.vNext.SDK; using SkyCD.vNext.SDK.Capabilities; using System.Threading.Tasks; namespace SkyCD.Plugin.WebBrowser { public class WebBrowserPlugin : IPlugin, IMenuPluginCapability { public Task InitializeAsync(IPluginHost host) { return Task.CompletedTask; } public MenuCommand GetMenuCommand() { return new MenuCommand { CommandId = "webbrowser.open", Title = "Web Browser", Location = "Tools", Order = 100 }; } public async Task ExecuteMenuCommandAsync(IMenuCommandContext context) { // URL resolution precedence: context -> config -> fallback var url = context.Properties.TryGetValue("url", out var contextUrl) ? contextUrl.ToString() : null; if (string.IsNullOrEmpty(url)) { var settings = await context.Host.GetPluginSettingsAsync(); url = settings.TryGetValue("defaultUrl", out var configUrl) ? configUrl.ToString() : null; } if (string.IsNullOrEmpty(url)) url = "about:blank"; if (!IsValidUrlScheme(url)) { await context.Host.NotifyUserAsync("Invalid URL scheme. Allowed: http, https, about"); return; } await LaunchUrlAsync(url, context.Host); } private bool IsValidUrlScheme(string url) { if (System.Uri.TryCreate(url, System.UriKind.Absolute, out var uri)) { return new[] { "http", "https", "about" }.Contains(uri.Scheme.ToLowerInvariant()); } return false; } private async Task LaunchUrlAsync(string url, IPluginHost host) { try { await host.LaunchExternalUrlAsync(url); } catch (System.Exception ex) { await host.NotifyUserAsync($"Failed to open URL: {ex.Message}"); } } } }